#include <stdio.h>
#include <windows.h>

#define SIZE 100

void bubbleSort(int *arr, int n) {
    int i, j, temp;
    for (i = 0; i < n - 1; i++) {
        for (j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                // 交换两个元素
                temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

int main() {
    int arr[SIZE];
    int i;
    LARGE_INTEGER frequency, startingTime, endingTime;
    double elapsedTime;

    for (i = 0; i < SIZE; i++) {
        scanf("%d", &arr[i]);
    }

    QueryPerformanceFrequency(&frequency);
    QueryPerformanceCounter(&startingTime);

    bubbleSort(arr, SIZE);

    QueryPerformanceCounter(&endingTime);

    elapsedTime = (double)(endingTime.QuadPart - startingTime.QuadPart) * 1000000.0 / frequency.QuadPart;

    printf("执行时间：%f 微秒\n", elapsedTime);

    return 0;
}
