#include <stdio.h>
#include <windows.h>

#define SIZE 100

void quickSort(int arr[], int low, int high);
int partition(int arr[], int low, int high);
void swap(int* a, int* b);

int main() {
    int arr[SIZE], i;
    LARGE_INTEGER frequency, start, end;
    double elapsedTime;

    for (i = 0; i < SIZE; i++) {
        scanf("%d", &arr[i]);
    }

    QueryPerformanceFrequency(&frequency);
    QueryPerformanceCounter(&start);

