#include <stdio.h>
#include <windows.h>

#define SIZE 100
#define NUM_SEARCHES 5

// 二分查找算法，返回所查找元素在数组中的位置，没有找到返回-1
int binarySearch(int arr[], int l, int r, int x) {
    while (l <= r) {
        int m = l + (r - l) / 2;

        if (arr[m] == x)
            return m + 1; // 数组是从0开始索引的，需要加1
        if (arr[m] < x)
            l = m + 1;
        else
            r = m - 1;
    }

    return -1; // 元素不在数组中
}

int main() {
    int arr[SIZE];
    int results[NUM_SEARCHES];
    int numbersToFind[NUM_SEARCHES] = {41, 53, 85, 27, 79};
