    // 因为折半查找要求有序数组，所以先对数组进行排序
    // 注意：排序时间不计入测量时间
    qsort(arr, SIZE, sizeof(int), (int (*)(const void *, const void *))strcmp);

    QueryPerformanceFrequency(&freq); // 获取计数器的频率
    QueryPerformanceCounter(&start);  // 获取开始时钟计数

