为了解决这个问题，我们必须先为给定频率的单词构建一个哈夫曼树，然后计算它的带权路径长度（PWL）。哈夫曼树是一种将频率用作权值的优先级队列来构建的贪心算法。

C语言的代码示例如下：

```c
#include <stdio.h>
#include <stdlib.h>

#define MAX_TREE_SIZE 1024

typedef struct {
    int weight;
    int parent, lchild, rchild;
} HTNode, *HuffmanTree;

typedef char * *HuffmanCode;

// 比较两个HTNode的函数
int cmp(const void *a, const void *b) {
    return ((HTNode *)a)->weight - ((HTNode *)b)->weight;
}

// 初始化哈夫曼树
void initHuffmanTree(HuffmanTree *ht, int n) {
    if(n <= 1) return;
    int m = 2 * n - 1;
    *ht = (HuffmanTree)malloc((m + 1) * sizeof(HTNode));
    for(int i = 1; i <= m; ++i) {
        (*ht)[i].weight = 0;
        (*ht)[i].parent = 0;
        (*ht)[i].lchild = 0;
        (*ht)[i].rchild = 0;
    }
}

// 构建哈夫曼树
void buildHuffmanTree(HuffmanTree ht, int *w, int n) {
    if(n <= 1) return;
    int m = 2 * n - 1;
    initHuffmanTree(&ht, n);
    for(int i = 1; i <= n; ++i)
        ht[i].weight = w[i-1];
    qsort(ht + 1, n, sizeof(HTNode), cmp); // 给叶子节点排序
    for(int i = n + 1; i <= m; ++i) {
        int s1 = i - 2, s2 = i - 1; // 已经排序，只需选取权值最小的两个节点
        ht[i].weight = ht[s1].weight + ht[s2].weight;
        ht[i].lchild = s1;
        ht[i].rchild = s2;
        ht[s1].parent = i;
        ht[s2].parent = i;
        qsort(ht + i, m - i + 1, sizeof(HTNode), cmp); // 给非叶子节点排序
    }
}

// 计算哈夫曼树的带权路径长度
int calculateWPL(HuffmanTree ht, int n) {
    int wpl = 0;
    for(int i = 1; i <= n; ++i) {
        int weight = ht[i].weight;
        int depth = 0;
        for(int j = i; ht[j].parent != 0; j = ht[j].parent)
            ++depth;
        wpl += weight * depth;
    }
    return wpl;
}

int main() {
    int t, n;
    scanf("%d", &t);
    HuffmanTree ht;
    while(t--) {
        int weights[MAX_TREE_SIZE], i = 0;
        while(scanf("%d", &weights[i]), weights[i]) i++;
        n = i;
        buildHuffmanTree(ht, weights, n);
        printf("%d\n", calculateWPL(ht, n));
        free(ht);
    }
    return 0;
}
```

这个程序首先读取测试数据的组数，然后依次读取每组数据的权值（频率），构建哈夫曼树，并计算它的WPL。

